import{_ as a,o as t,c as o,a2 as i}from"./chunks/framework.Bix3-HpO.js";const m=JSON.parse('{"title":"Creating Review Pages","description":"Creating Review Pages with Kemoku Plugin","frontmatter":{"title":"Creating Review Pages","description":"Creating Review Pages with Kemoku Plugin","weight":40,"extra":{"order":40},"head":[["link",{"rel":"canonical","href":"https://docs.dinomatic.com/docs/kemoku/review-pages"}],["meta",{"property":"og:url","content":"https://docs.dinomatic.com/docs/kemoku/review-pages"}],["meta",{"property":"og:title","content":"Creating Review Pages"}],["meta",{"property":"og:description","content":"Creating Review Pages with Kemoku Plugin"}],["meta",{"name":"twitter:title","content":"Creating Review Pages"}],["meta",{"name":"twitter:description","content":"Creating Review Pages with Kemoku Plugin"}]]},"headers":[],"relativePath":"docs/kemoku/review-pages.md","filePath":"docs/kemoku/review-pages.md"}'),n={name:"docs/kemoku/review-pages.md"};function r(s,e,d,l,c,h){return t(),o("div",null,[...e[0]||(e[0]=[i('<h1 id="creating-review-pages" tabindex="-1">Creating Review Pages <a class="header-anchor" href="#creating-review-pages" aria-label="Permalink to &quot;Creating Review Pages&quot;">​</a></h1><p>In your WordPress dashboard you will find a new menu called <strong>Kemoku Reviews</strong> right below the <strong>Pages</strong> menu link. Click <code>Add New</code> to add a new review.</p><hr><h2 id="review-fields" tabindex="-1">Review Fields <a class="header-anchor" href="#review-fields" aria-label="Permalink to &quot;Review Fields&quot;">​</a></h2><p>Besides adding your review title and content as usual, you&#39;ll find <strong>Review Fields</strong> section below page content. Here you can define properties for each review. The fields are in separate sections and have descriptions to make it easy for you to fill them in. To see what they look like you can check one of the demos available <a href="https://demos.dinomatic.com/havana" target="_blank" rel="noreferrer">here</a>.</p><p><img src="https://media.dinomatic.com/images/docs/kemoku/kemoku-review-fields.webp" alt="General Review Fields"></p><h3 id="general-fields" tabindex="-1">General Fields <a class="header-anchor" href="#general-fields" aria-label="Permalink to &quot;General Fields&quot;">​</a></h3><p>Define main review information such as the name, logo, affiliate URL, rating. All fields in this section are required.</p><h3 id="bonus-terms-fields" tabindex="-1">Bonus &amp; Terms Fields <a class="header-anchor" href="#bonus-terms-fields" aria-label="Permalink to &quot;Bonus &amp; Terms Fields&quot;">​</a></h3><p>Define bonus, bonus code (if any) and terms that can be the full terms and conditions text and/or a URL.</p><h3 id="payments-currencies" tabindex="-1">Payments &amp; Currencies <a class="header-anchor" href="#payments-currencies" aria-label="Permalink to &quot;Payments &amp; Currencies&quot;">​</a></h3><p>Define <em>Payment Methods</em> and <em>Currencies</em> for the reviewed item and display them in your content through <code>Review Payments</code> and <code>Currencies</code> block. Payment method and currency information is also used for filtering review listings.</p><h3 id="details" tabindex="-1">Details <a class="header-anchor" href="#details" aria-label="Permalink to &quot;Details&quot;">​</a></h3><p>Define some details such as <em>Services, Sports, Licenses, Features</em> for the reviewed item. Services and sports can be displayed using <code>Review Services</code> and <code>Review Sports</code> blocks. They can be also used in listing filters along with features.</p><h3 id="hero-section" tabindex="-1">Hero Section <a class="header-anchor" href="#hero-section" aria-label="Permalink to &quot;Hero Section&quot;">​</a></h3><p>Define whether the <em>Hero</em> section at the top of the review page is enabled or not. Hero section settings can be adjusted on <a href="/docs/kemoku/settings#hero">plugin settings page</a></p><h3 id="cta-section" tabindex="-1">CTA Section <a class="header-anchor" href="#cta-section" aria-label="Permalink to &quot;CTA Section&quot;">​</a></h3><p>Define whether the <em>CTA</em> section at the bottom of the review page is enabled or not, as well as fill in the CTA details. CTA section settings can be adjusted on <a href="/docs/kemoku/settings#cta">plugin settings page</a></p><h3 id="pros-cons" tabindex="-1">Pros &amp; Cons <a class="header-anchor" href="#pros-cons" aria-label="Permalink to &quot;Pros &amp; Cons&quot;">​</a></h3><p>Define <em>Pros &amp; Cons</em> of the reviewed item and display it in your content through <code>Review Pros &amp; Cons</code> block.</p><h3 id="ratings" tabindex="-1">Ratings <a class="header-anchor" href="#ratings" aria-label="Permalink to &quot;Ratings&quot;">​</a></h3><p>Define <em>Ratings</em> of the reviewed item and display it in your content through <code>Review Ratings</code> block.</p><h3 id="info" tabindex="-1">Info <a class="header-anchor" href="#info" aria-label="Permalink to &quot;Info&quot;">​</a></h3><p>Define <em>Review Info</em> fields for the reviewed item and display it in your content through <code>Review Info</code> block.</p><h3 id="geo-targeting" tabindex="-1">Geo Targeting <a class="header-anchor" href="#geo-targeting" aria-label="Permalink to &quot;Geo Targeting&quot;">​</a></h3><p>Here you can define supported or restricted countries for the reviewed item. Fill just one of teh fields, whichever information is available to you. Do NOT fill in both fields, in that case &quot;Restricted Countries&quot; will be used.</p><p>You can also define supported US States in this section.</p><p>If the operators provide you with different affiliate links for different regions, you can use &quot;Affiliate Links&quot; field to add as many country-specific links as you want. Simply choose a country and add a link.</p><h3 id="schema-org-markup" tabindex="-1">Schema.org markup <a class="header-anchor" href="#schema-org-markup" aria-label="Permalink to &quot;Schema.org markup&quot;">​</a></h3><p>For all your review pages the plugin generates <strong>Review Snippet Structured Data</strong> (schema.org) markup. The rating value used is the &quot;Rating&quot; field from &quot;Bonus &amp; Rating&quot; section. It is generated automatically so you don&#39;t need to do anything. You can test your pages <a href="https://search.google.com/structured-data/testing-tool" target="_blank" rel="noreferrer">here</a>.</p><p>By default the review snippet author is set as &quot;Organization&quot; and the name is your website title.</p><p><code>💁 since version 1.5.2</code> you can change the author to &quot;Person&quot; and that would be the review page author. You can do that in Kemoku Settings → <a href="/docs/kemoku/settings#general-settings">General</a>.</p><h3 id="taxonomies" tabindex="-1">Taxonomies <a class="header-anchor" href="#taxonomies" aria-label="Permalink to &quot;Taxonomies&quot;">​</a></h3><p><code>💁 since version 1.5</code> you can assign <strong>Categories</strong> and <strong>Tags</strong> to review pages, and you can filter reviews on tables and grids by category and tag as well.</p>',34)])])}const g=a(n,[["render",r]]);export{m as __pageData,g as default};
